mapper.select:
SELECT report_id FROM sys_ai_report
WHERE user_id = #{userSn} AND diagnosis_id = #{diagnosisId} AND report_type = #{reportType}
ORDER BY report_id DESC LIMIT 1

mapper.update:
UPDATE sys_ai_report
SET banner_title = #{bannerTitle}, subtitle = #{subtitle}, keywords = #{keywords}
WHERE report_id = #{reportId}

mapper.delete:
DELETE s FROM sys_report_competency_source s
JOIN sys_report_competency c ON c.competency_id = s.competency_id
WHERE c.report_id = #{reportId}
  AND c.fit_type IN
  #{t}

